This is the template for the dsu class<div class="mac-code"><div class="mac-code-header" contenteditable="false"><span class="dot red"></span><span class="dot yellow"></span><span class="dot green"></span></div><pre><code>#include &lt;bits/stdc++.h&gt;
using namespace std;
using ll = long long;

void solve() {
  int N;
  cin &gt;&gt; N;
  vector&lt;int&gt; P(N);
  for (int i = 1; i &lt; N; ++i) {
    P[i] = i ^ P[i - 1];
  }
  ll res = 0;
  for (int _ = 0; _ &lt; N; ++_) {
    ll x;
    cin &gt;&gt; x;
    res ^= x;
  }
  for (int k = 1; k &lt;= N; ++k) {
    res ^= ((((N / k) % 2) * (P[k - 1])) ^ P[N % k]);
  }
  cout &lt;&lt; res &lt;&lt; "\n";
}

int main() {
  ios::sync_with_stdio(false);
  cin.tie(0);
  solve();
  return 0;
}</code></pre></div><p><br></p>
